from elftools.elf.elffile import ELFFile
from elftools.elf.sections import SymbolTableSection

with open('libmonosgen-2.0.so.debug', 'rb') as f:
    elf = ELFFile(f)
    symtab = elf.get_section_by_name('.symtab')
    if not symtab:
        print('No symtab')
    else:
        targets = [0x2f4b20, 0x2f4c84]
        for target in targets:
            best = None
            for sym in symtab.iter_symbols():
                if sym['st_info']['type'] in ('STT_FUNC', 'STT_OBJECT'):
                    start = sym['st_value']
                    end = start + sym['st_size']
                    if start <= target < end:
                        if best is None or sym['st_size'] < best['st_size']:
                            best = sym
                    elif start <= target and (best is None or start > best['st_value']):
                        if best is None:
                            best = sym
            if best:
                print(f'0x{target:x} -> {best.name} + 0x{target - best[\"st_value\"]:x} (0x{best[\"st_value\"]:x}, size=0x{best[\"st_size\"]:x})')
            else:
                print(f'0x{target:x} -> ???')
"

